package sn.gestionimmobiliere.backend.identity.application;
import org.springframework.security.authentication.BadCredentialsException;import org.springframework.security.crypto.password.PasswordEncoder;import org.springframework.stereotype.Service;import sn.gestionimmobiliere.backend.identity.api.*;import sn.gestionimmobiliere.backend.identity.domain.AppUser;import sn.gestionimmobiliere.backend.identity.infrastructure.AppUserRepository;
@Service public class AuthService{private final AppUserRepository users;private final PasswordEncoder encoder;private final JwtService jwt;private final SecurityProperties props;public AuthService(AppUserRepository u,PasswordEncoder e,JwtService j,SecurityProperties p){users=u;encoder=e;jwt=j;props=p;}public LoginResponse login(LoginRequest r){AppUser u=users.findByEmailIgnoreCaseAndStatus(r.email().trim(),"ACTIVE").orElseThrow(()->new BadCredentialsException("Identifiants invalides"));if(!encoder.matches(r.password(),u.getPasswordHash()))throw new BadCredentialsException("Identifiants invalides");return new LoginResponse(jwt.create(u),"Bearer",props.tokenValidityMinutes()*60,u.getFullName(),u.getRole().name());}}
